@function color-luminance($color) {
  // Adapted from: https://github.com/LeaVerou/contrast-ratio/blob/gh-pages/color.js
  // Formula: http://www.w3.org/TR/2008/REC-WCAG20-20081211/#relativeluminancedef
  $red   : round(color.channel($color, "red", $space: rgb));
  $green : round(color.channel($color, "green", $space: rgb));
  $blue  : round(color.channel($color, "blue", $space: rgb));

  $rgba: $red, $green, $blue;
  $rgba2: ();

  @for $i from 1 through 3 {
    $rgb: nth($rgba, $i);
    $rgb: divide($rgb, 255);

    $rgb: if($rgb < 0.03928, divide($rgb, 12.92), pow(divide($rgb + 0.055, 1.055), 2.4));

    $rgba2: append($rgba2, $rgb);
  }

  @return 0.2126 * nth($rgba2, 1) + 0.7152 * nth($rgba2, 2) + 0.0722 * nth($rgba2, 3);
}

@function _compact-shorthand($values) {
  $output: null;

  $a: nth($values, 1);
  $b: if(length($values) < 2, $a, nth($values, 2));
  $c: if(length($values) < 3, $a, nth($values, 3));
  $d: if(length($values) < 2, $a, nth($values, if(length($values) < 4, 2, 4)));

  @if $a == 0 { $a: 0; }
  @if $b == 0 { $b: 0; }
  @if $c == 0 { $c: 0; }
  @if $d == 0 { $d: 0; }

  @if $a == $b and $a == $c and $a == $d {
    $output: $a;
  } @else if $a == $c and $b == $d {
    $output: $a $b;
  } @else if $b == $d {
    $output: $a $b $c;
  } @else {
    $output: $a $b $c $d;
  }

  @return $output;
}

@function subtract($value1, $value2, $return-calc: true) {
  @if $value1 == null and $value2 == null {
    @return null;
  }

  @if $value1 == null {
    @return -$value2;
  }

  @if $value2 == null {
    @return $value1;
  }

  @if type-of($value1) == number and type-of($value2) == number and comparable($value1, $value2) {
    @return $value1 - $value2;
  }

  @if type-of($value2) != number {
    $value2: unquote("(") + $value2 + unquote(")");
  }

  @return if($return-calc == true, calc(#{$value1} - #{$value2}), $value1 + unquote(" - ") + $value2);
}

@function color-translucent($target-color, $alpha: .1, $bg-color: #fff) {
  @if color.alpha($target-color) < 1 {
    @return $target-color;
  }

  @if $alpha <= 0 or $alpha > 1 {
    @error "Alpha must be greater than 0 and less than or equal to 1.";
  }

  $r: math.div(
    color.channel($target-color, "red") - color.channel($bg-color, "red") * (1 - $alpha),
    $alpha
  );

  $g: math.div(
    color.channel($target-color, "green") - color.channel($bg-color, "green") * (1 - $alpha),
    $alpha
  );

  $b: math.div(
    color.channel($target-color, "blue") - color.channel($bg-color, "blue") * (1 - $alpha),
    $alpha
  );

  @if $r < 0 or $r > 255 or $g < 0 or $g > 255 or $b < 0 or $b > 255 {
    @error "Cannot reproduce #{$target-color} on #{$bg-color} with alpha #{$alpha}. Try a higher alpha.";
  }

  @return rgba(round($r), round($g), round($b), $alpha);
}

@function zf-parse-fraction($fraction) {

  @if type-of($fraction) == 'number' {
    // "50%"
    @if unit($fraction) == '%' {
      @return (strip-unit($fraction), 100);
    }
    @else if (unit($fraction) == '') {
      // "0.5"
      @if $fraction < 1 {
        @return ($fraction * 100, 100);
      }
      // "50"
      @else {
        @return ($fraction, null);
      }
    }
  }

  @else if type-of($fraction) == 'list' {
    // "50 of 100", "50/100"...
    @if length($fraction) == 3
    and type-of(nth($fraction, 1) == 'number')
    and type-of(nth($fraction, 3) == 'number') {
      @return (nth($fraction, 1), nth($fraction, 3));
    }
  }

  @return (null, null);
}

@function _font-source-declaration(
  $font-family,
  $file-path,
  $asset-pipeline,
  $file-formats
) {
  $src: ();

  $formats-map: (
    "woff2": "#{$file-path}.woff2" format("woff2"),
    "woff": "#{$file-path}.woff" format("woff"),
  );

  @each $format in $file-formats {
    @if _contains(map-keys($formats-map), $format) {
      $value: map-get($formats-map, $format);
      $file-path: nth($value, 1);
      $font-format: nth($value, 2);

      @if $asset-pipeline == true {
        $src: append($src, font-url($file-path) $font-format, comma);
      } @else {
        $src: append($src, url($file-path) $font-format, comma);
      }
    } @else {
      @error "`#{$file-formats}` contains an unsupported font file format. " +
        "Must be `woff` and/or `woff2`.";
    }
  }

  @return $src;
}

@include breakpoint($breakpoint, $breakpoints) {
  // Provide basic `.col-{bp}` classes for equal-width flexbox columns
  .#{$prefix}--col,
  .#{$prefix}--col#{$infix} {
    flex-basis: 0;
    flex-grow: 1;
    max-inline-size: 100%;
  }

  .#{$prefix}--col--auto,
  .#{$prefix}--col#{$infix}--auto {
    flex: 1 0 0%;
    inline-size: auto;
    // Reset earlier grid tiers
    max-inline-size: 100%;
  }

  @for $i from 0 through $columns {
    .#{$prefix}--col#{$infix}-#{$i} {
      @include -make-col($i, $columns);
    }
  }

  @for $i from 0 through ($columns - 1) {
    @if not($infix == '') {
      .#{$prefix}--offset#{$infix}-#{$i} {
        @include -make-col-offset($i, $columns);
      }
    }
  }
}

@mixin box-shadow($shadow...) {
  @if $enable-shadows {
    $result: ();
    $has-single-value: false;
    $single-value: null;

    @each $value in $shadow {
      @if $value != null {
        @if $value == none or $value == initial or $value == inherit or $value == unset {
          $has-single-value: true;
          $single-value: $value;
        } @else {
          $result: append($result, $value, "comma");
        }
      }
    }

    @if $has-single-value {
      box-shadow: $single-value;
    } @else if (length($result) > 0) {
      box-shadow: $result;
    }
  }
}

