    } @else if (list.length($result) > 0) {
      box-shadow: $result;
    }
  }
}

@mixin button-outline-variant(
  $color,
  $hover-color,
  $focus-color,
  $active-color,
  $hover-background: tint-color($color, $btn-outline-hover-bg-tint-amount),
  $focus-background: tint-color($color, $btn-outline-focus-bg-tint-amount),
  $active-background: tint-color($color, $btn-outline-active-bg-tint-amount)
) {
  --#{$prefix}btn-bg: transparent;
  --#{$prefix}btn-color: #{$color};
  --#{$prefix}btn-hover-bg: #{$hover-background};
  --#{$prefix}btn-hover-color: #{$hover-color};
  --#{$prefix}btn-focus-bg: #{$focus-background};
  --#{$prefix}btn-focus-color: #{$focus-color};
  --#{$prefix}btn-active-bg: #{$active-background};
  --#{$prefix}btn-active-color: #{$active-color};
}

// Layout
.container {
  margin-left: auto;
  margin-right: auto;
  padding-left: $layout-spacing;
  padding-right: $layout-spacing;
  width: 100%;

  $grid-spacing: ($layout-spacing / ($layout-spacing * 0 + 1)) * $html-font-size;

  &.grid-xl {
    max-width: $grid-spacing * 2 + $size-xl;
  }

  &.grid-lg {
    max-width: $grid-spacing * 2 + $size-lg;
  }

  &.grid-md {
    max-width: $grid-spacing * 2 + $size-md;
  }

  &.grid-sm {
    max-width: $grid-spacing * 2 + $size-sm;
  }

  &.grid-xs {
    max-width: $grid-spacing * 2 + $size-xs;
  }
}

@mixin hook-inverse-component-tab(){

    .uk-tab {
        @if(meta.mixin-exists(hook-inverse-tab)) {@include hook-inverse-tab();}
    }

    .uk-tab > * > a {
        color: $inverse-tab-item-color;
        @if(meta.mixin-exists(hook-inverse-tab-item)) {@include hook-inverse-tab-item();}
    }

    .uk-tab > * > a:hover {
        color: $inverse-tab-item-hover-color;
        @if(meta.mixin-exists(hook-inverse-tab-item-hover)) {@include hook-inverse-tab-item-hover();}
    }

    .uk-tab > .uk-active > a {
        color: $inverse-tab-item-active-color;
        @if(meta.mixin-exists(hook-inverse-tab-item-active)) {@include hook-inverse-tab-item-active();}
    }

    .uk-tab > .uk-disabled > a {
        color: $inverse-tab-item-disabled-color;
        @if(meta.mixin-exists(hook-inverse-tab-item-disabled)) {@include hook-inverse-tab-item-disabled();}
    }

}

@else {
  @include breakpoint($name) {
    // Responsive column start
    @for $i from 1 through get-grid-columns($breakpoints) {
      .#{$prefix}--#{$name}\:col-start-#{$i} {
        grid-column-start: $i;
      }
    }

    // Responsive column end
    @for $i from 2 through get-grid-columns($breakpoints) + 1 {
      .#{$prefix}--#{$name}\:col-end-#{$i} {
        grid-column-end: $i;
      }
    }

    .#{$prefix}--#{$name}\:col-start-auto {
      grid-column-start: auto;
    }

    .#{$prefix}--#{$name}\:col-end-auto {
      grid-column-end: auto;
    }
  }
}

@mixin -make-container($breakpoints: $grid-breakpoints) {
  margin-inline: auto;

  @include -set-largest-breakpoint();

  @each $name, $value in $breakpoints {
    $prev-breakpoint: map.get($breakpoints, breakpoint-prev($name));
    $margin: map.get($value, margin);

    @if $prev-breakpoint {
      $prev-margin: map.get($prev-breakpoint, margin);
      @if $prev-margin != $margin {
        @include breakpoint($name) {
          padding-inline: #{($grid-gutter * 0.5) + $margin};
        }
      }
    } @else {
      @include breakpoint($name) {
        padding-inline: #{($grid-gutter * 0.5) + $margin};
      }
    }
  }
}

@mixin grid(
  $breakpoints: $grid-breakpoints,
  $grid-gutter: $grid-gutter,
  $condensed-gutter: $grid-gutter--condensed
) {
  .#{$prefix}--grid {
    @include -make-container($breakpoints);
  }

  @include largest-breakpoint($breakpoints) {
    .#{$prefix}--grid--full-width {
      max-inline-size: 100%;
    }
  }

  .#{$prefix}--row {
    @include make-row();
  }

  .#{$prefix}--row-padding [class*='#{$prefix}--col'],
  .#{$prefix}--col-padding {
    padding-block: $grid-gutter * 0.5;
  }

  .#{$prefix}--grid--condensed [class*='#{$prefix}--col'] {
    padding-block: $condensed-gutter * 0.5;
  }

  @include -make-grid-columns($breakpoints, $grid-gutter);
  @include -no-gutter();
  @include -hang($grid-gutter);
}

@mixin badge-indicator {
  .#{$prefix}--badge-indicator {
    @include type.type-style('helper-text-01');

    position: absolute;
    display: flex;
    padding: 0 $spacing-02 $spacing-01;
    border-radius: 100px;
    background: $support-error;
    color: $text-on-color;

    inset-block-start: 0;
    inset-inline-end: 0;

    margin-block-start: $spacing-03;
    margin-inline-end: $spacing-03;

    max-block-size: $spacing-05;
    min-block-size: $spacing-03;
    min-inline-size: $spacing-03;
  }

  .#{$prefix}--badge-indicator--count {
    margin-block-start: $spacing-02;
    margin-inline-end: $spacing-02;
  }
}

button.#{$prefix}--btn {
  position: relative;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  margin: 0;
  block-size: 100%;
  min-block-size: 100%;
  padding-inline-end: $spacing-05;
  padding-inline-start: $spacing-05;

  &::before {
    @media (prefers-reduced-motion: reduce) {
      transition: none;
    }

    position: absolute;
    display: block;
    border: none;
    background-color: $text-on-color;
    block-size: $spacing-05;
    content: '';
    inline-size: rem(1px);
    inset-inline-start: 0;
    opacity: var(--divider-opacity);
    transition: opacity $duration-fast-02 motion(standard, productive);
  }

  &:hover::before {
    opacity: 0;
  }
}

@for $spacer from 0 through $prototype-spacers-count {

  @each $prop in (margin, padding) {
    // All Sides
    .#{$prop}-#{$spacer} {
      @if ($prop == margin) {
        margin: $spacer * $global-margin !important;
      }
      @else if ($prop == padding) {
        padding: $spacer * $global-padding !important;
      }
    }

    @each $dir in (top, right, bottom, left, horizontal, vertical) {
      // Top Side
      .#{$prop}-#{$dir}-#{$spacer} {
        @if ($prop == margin) {
          @include margin-direction($dir, $spacer);
        }
        @else if ($prop == padding) {
          @include padding-direction($dir, $spacer);
        }
      }
    }
  }
}

@mixin xy-cell-static(
  $size: full,
  $gutter-output: true,
  $gutters: $grid-margin-gutters,
  $gutter-type: margin,
  $breakpoint: $-zf-zero-breakpoint,
  $vertical: false
) {
  @warn 'xy-cell-static() mixin is deprecated and will be removed. Use "xy-cell()" instead. See migration notes at https://git.io/foundation-6-6-0';

  $gutter: -zf-get-bp-val($gutters, $breakpoint);
  $gutter-position: if($vertical == true, top bottom, left right);

  $-gutter-output: if($gutter-type == 'margin', true, $gutter-output);
  $-gutter-margin: if($gutter-type == 'margin', $gutter, 0);

  @include -xy-cell-properties($size, $-gutter-margin, $vertical);
  @if ($-gutter-output) {
    @include xy-gutters($gutter, $gutter-type, $gutter-position);
  }
}

@mixin box-shadow($shadow...) {
  @if $enable-shadows {
    $result: ();
    $has-single-value: false;
    $single-value: null;

    @each $value in $shadow {
      @if $value != null {
        @if $value == none or $value == initial or $value == inherit or $value == unset {
