@mixin typeset(
  $family: $theme-body-font-family,
  $scale: $theme-body-font-size,
  $line-height: $theme-body-line-height
) {
  @if meta.type-of($family) == "list" {
    $list: $family;
    $family: if(list.nth($list, 1), list.nth($list, 1), null);
    $scale: if(list.nth($list, 2), list.nth($list, 2), null);
    $line-height: if(list.nth($list, 3), list.nth($list, 3), null);
  }
  $family: if($family == null, $theme-body-font-family, $family);
  $scale: if($scale == null, $theme-body-font-size, $scale);
  $line-height: if($line-height == null, $theme-body-line-height, $line-height);
  @include u-font($family, $scale);
  @include u-line-height($family, $line-height);
}

@mixin aspect-ratio($aspect-ratios: $aspect-ratios) {
  .#{$prefix}--aspect-ratio {
    position: relative;
  }

  .#{$prefix}--aspect-ratio::before {
    block-size: 0;
    content: '';
    // float: inline-start is not supported yet
    // https://caniuse.com/mdn-css_properties_float_flow_relative_values
    // stylelint-disable-next-line csstools/use-logical
    float: left;
    inline-size: 1px;
    margin-inline-start: -1px;
  }

  .#{$prefix}--aspect-ratio::after {
    display: table;
    clear: both;
    content: '';
  }

  @each $aspect-ratio in $aspect-ratios {
    $width: list.nth($aspect-ratio, 1);
    $height: list.nth($aspect-ratio, 2);

    .#{$prefix}--aspect-ratio--#{$width}x#{$height}::before {
      padding-block-start: math.percentage(math.div($height, $width));
    }
  }
}

@function _define-overrides() {
  @return (
    (
      namespace: app,
      tokens: token-utils.get-overrides(m3-app.get-tokens(), app),
      prefix: 'app-'
    ),
    (
      namespace: ripple,
      tokens: token-utils.get-overrides(m3-ripple.get-tokens(), ripple),
      prefix: 'ripple-'
    ),
    (
      namespace: option,
      tokens: token-utils.get-overrides(m3-option.get-tokens(), option),
      prefix: 'option-'
    ),
    (
      namespace: optgroup,
      tokens: token-utils.get-overrides(m3-optgroup.get-tokens(), optgroup),
      prefix: 'optgroup-'
    ),
    (
      namespace: pseudo-checkbox,
      tokens: token-utils.get-overrides(m3-pseudo-checkbox.get-tokens(), pseudo-checkbox),
      prefix: 'pseudo-checkbox-'
    ),
  );
}

@else {
  $previous-breakpoint: breakpoint-prev($key, $breakpoints);
  $changes: ();

  @if get-column-count($breakpoints, $key) !=
    get-column-count($breakpoints, $previous-breakpoint)
  {
    $changes: map.set(
      $changes,
      grid-columns,
      get-column-count($breakpoints, $key)
    );
  }

  @if get-margin($breakpoints, $key) !=
    get-margin($breakpoints, $previous-breakpoint)
  {
    $changes: map.set(
      $changes,
      grid-margin,
      get-margin($breakpoints, $key)
    );
  }

  @include breakpoint($key) {
    @each $name, $value in $changes {
      --cds-#{$name}: #{$value};
    }
  }
}

@if is-smallest-breakpoint($name, $breakpoints) {
  .#{$prefix}--#{$name}\:col-span-auto {
    grid-column: auto;
  }

  .#{$prefix}--#{$name}\:col-span-100 {
    grid-column: 1 / -1;
  }

  $columns: get-column-count($breakpoints, $name);

  .#{$prefix}--#{$name}\:col-span-75 {
    $span: $columns * 0.75;
    --cds-grid-columns: #{$span};

    grid-column: span list.slash($span, span) #{$span};
  }

  .#{$prefix}--#{$name}\:col-span-50 {
    $span: $columns * 0.5;
    --cds-grid-columns: #{$span};

    grid-column: span list.slash($span, span) #{$span};
  }

  .#{$prefix}--#{$name}\:col-span-25 {
    $span: $columns * 0.25;
    --cds-grid-columns: #{$span};

    grid-column: span list.slash($span, span) #{$span};
  }
}

@include breakpoint($name) {
  .#{$prefix}--#{$name}\:col-span-auto {
    grid-column: auto;
  }

  .#{$prefix}--#{$name}\:col-span-100 {
    grid-column: 1 / -1;
  }

  $columns: get-column-count($breakpoints, $name);

  .#{$prefix}--#{$name}\:col-span-75 {
    $span: $columns * 0.75;
    --cds-grid-columns: #{$span};

    grid-column: span list.slash($span, span) #{$span};
  }

  .#{$prefix}--#{$name}\:col-span-50 {
    $span: $columns * 0.5;
    --cds-grid-columns: #{$span};

    grid-column: span list.slash($span, span) #{$span};
  }

  .#{$prefix}--#{$name}\:col-span-25 {
    $span: $columns * 0.25;
    --cds-grid-columns: #{$span};

    grid-column: span list.slash($span, span) #{$span};
  }
}

@mixin sticky-header(
  $min-width: false,
  $max-width: 100%,
  $max-height: convert.to-rem(300px)
) {
  .#{$prefix}--data-table--max-width {
    max-inline-size: $max-width;
  }

  .#{$prefix}--data-table--sticky-header {
    max-block-size: $max-height;

    @if $min-width {
      th:not(.#{$prefix}--table-column-checkbox):not(
          .#{$prefix}--table-column-menu
        ):not(.#{$prefix}--table-expand):not(.#{$prefix}--table-column-icon),
      td:not(.#{$prefix}--table-column-checkbox):not(
          .#{$prefix}--table-column-menu
        ):not(.#{$prefix}--table-expand):not(.#{$prefix}--table-column-icon) {
        min-inline-size: $min-width;
      }
    }
  }
}

@mixin pseudo-underline() {
  &:not(.#{$prefix}--pagination-nav__page--direction) {
    &::after {
      position: absolute;
      display: block;
      background-color: $border-interactive;
      block-size: $spacing-02;
      content: '';
      inline-size: 0;
      inset-block-end: 0;
      inset-inline-start: 50%;
      opacity: 0;
      transition: width $duration-fast-02 motion(standard, productive);

      @media screen and (prefers-reduced-motion: reduce) {
        transition: none;
      }
    }
  }

  .#{$prefix}--pagination-nav__page--active + &::after,
  &.#{$prefix}--pagination-nav__page--active::after {
    inline-size: $spacing-05;
    inset-inline-start: calc(50% - #{$spacing-05 * 0.5});
    opacity: 1;
  }
}

&#{$base-selector} {
  // Do not generate button base styles for the default filling
  @if($button-fill != $filling) {
    #{$buttongroup-child-selector} {
      @include button-fill($filling);
      @include button-fill-style($filling);
    }
  }

  @each $name, $color in $button-palette {
    @if($button-fill != $filling) {
      $individual-selector: ' #{$buttongroup-child-selector}.#{"" + $name}';
      &.#{"" + $name} #{$buttongroup-child-selector}, &#{$individual-selector} {
        @include button-fill-style($filling, $color, auto, auto);
      }
    }
    @else {
      &.#{"" + $name} #{$buttongroup-child-selector} {
        @include button-fill-style($filling, $color, auto, auto);
      }
    }
  }
}

@each $filling in (solid hollow clear) {
  $base-selector: if($button-fill == $filling, null, '.#{$filling}');

  &#{$base-selector} {
    // Do not generate button base styles for the default filling
    @if($button-fill != $filling) {
      #{$buttongroup-child-selector} {
        @include button-fill($filling);
        @include button-fill-style($filling);
      }
    }

    @each $name, $color in $button-palette {
      @if($button-fill != $filling) {
